"use client"

import { useEnvironmentContext } from "@ark-ui/react"
import { useEffect, useRef, useState } from "react"

export function useElementRect() {
  const ref = useRef<HTMLElement | null>(null)
  const [rect, setRect] = useState<DOMRect | null>(null)
  const env = useEnvironmentContext()

  useEffect(() => {
    const node = ref.current
    if (!node) return

    const handleResize = () => {
      setRect(node.getBoundingClientRect())
    }

    const win = env.getWindow()
    if (!win) return

    const observer = new win.ResizeObserver(handleResize)
    observer.observe(node)

    return () => observer.disconnect()
  }, [env])

  return { ref, rect }
}

"use client"

import { useEffect, useRef } from "react"

export const useUpdateEffect: typeof useEffect = (effect, deps) => {
  const renderCycleRef = useRef(false)
  const effectCycleRef = useRef(false)

  useEffect(() => {
    const isMounted = renderCycleRef.current
    const shouldRun = isMounted && effectCycleRef.current
    if (shouldRun) {
      return effect()
    }
    effectCycleRef.current = true
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps)

  useEffect(() => {
    renderCycleRef.current = true
    return () => {
      renderCycleRef.current = false
    }
  }, [])
}

export function useAnimate<T extends Element = any>() {
    const scope: AnimationScope<T> = useConstant(() => ({
        current: null!, // Will be hydrated by React
        animations: [],
    }))

    const reduceMotion = useReducedMotionConfig() ?? undefined
    const { skipAnimations } = useContext(MotionConfigContext)

    const animate = useMemo(
        () => createScopedAnimate({ scope, reduceMotion, skipAnimations }),
        [scope, reduceMotion, skipAnimations]
    )

    useUnmountEffect(() => {
        scope.animations.forEach((animation) => animation.stop())
        scope.animations.length = 0
    })

    return [scope, animate] as [AnimationScope<T>, typeof animate]
}

export function useReducerAtom<Value, Action>(
  anAtom: PrimitiveAtom<Value>,
  reducer: (v: Value, a: Action) => Value,
  options?: Options,
) {
  if (import.meta.env?.MODE !== 'production') {
    console.warn(
      '[DEPRECATED] useReducerAtom is deprecated and will be removed in the future. Please create your own version using the recipe. https://github.com/pmndrs/jotai/pull/2467',
    )
  }
  const [state, setState] = useAtom(anAtom, options)
  const dispatch = useCallback(
    (action: Action) => {
      setState((prev) => reducer(prev, action))
    },
    [setState, reducer],
  )
  return [state, dispatch]
}

