const BUILDING_BLOCK_ensureAtomState: EnsureAtomState = (
  buildingBlocks,
  store,
  atom,
) => {
  const atomStateMap = buildingBlocks[0]
  let atomState = atomStateMap.get(atom)
  if (!atomState) {
    // Because ensureAtomState is a hot spot, we intentionally delay the evaluation even though this pattern is exceptional.
    // Ref: https://github.com/pmndrs/jotai/pull/3313
    const storeHooks = buildingBlocks[6]
    const atomOnInit = buildingBlocks[9]
    atomState = { d: new Map(), p: new Set(), n: 0 }
    atomStateMap.set(atom, atomState)
    storeHooks.i?.(atom)
    if (hasOnInit(atom)) {
      atomOnInit(buildingBlocks, store, atom)
    }
  }
  return atomState as never
}

import { ProgressTimeline } from "../animation/types"
import { cancelFrame, frame } from "../frameloop"

type Update = (progress: number) => void

export function observeTimeline(update: Update, timeline: ProgressTimeline) {
    let prevProgress: number

    const onFrame = () => {
        const { currentTime } = timeline
        const percentage = currentTime === null ? 0 : currentTime.value
        const progress = percentage / 100

        if (prevProgress !== progress) {
            update(progress)
        }

        prevProgress = progress
    }

    frame.preUpdate(onFrame, true)

    return () => cancelFrame(onFrame)
}

const hasExplicitNullIntermediate = (name: InternalFieldName) => {
  const segments = isKey(name) ? [name] : stringToPath(name);
  let formValues = _formValues;
  let defaultValues = _defaultValues;

  for (let i = 0; i < segments.length - 1; i++) {
    const key = segments[i];

    formValues = isNullOrUndefined(formValues) ? formValues : formValues[key];

    defaultValues = isNullOrUndefined(defaultValues)
      ? defaultValues
      : defaultValues[key as keyof typeof defaultValues];

    if (formValues === null && defaultValues !== null) {
      return true;
    }
  }

  return false;
};

import { ROOT_ERROR_TYPE } from '../constants';
