export default <T extends FieldValues = FieldValues>(
  errors: FieldErrors<T>,
  error: Partial<Record<string, FieldError>>,
  name: InternalFieldName,
): FieldErrors<T> => {
  const existingErrors = get(errors, name);
  const fieldArrayErrors = Array.isArray(existingErrors) ? existingErrors : [];
  set(fieldArrayErrors, ROOT_ERROR_TYPE, error[name]);
  set(errors, name, fieldArrayErrors);
  return errors;
};

function stripIndexParam(request: Request) {
  let url = new URL(request.url);
  let indexValues = url.searchParams.getAll("index");
  url.searchParams.delete("index");
  let indexValuesToKeep = [];
  for (let indexValue of indexValues) {
    if (indexValue) {
      indexValuesToKeep.push(indexValue);
    }
  }
  for (let toKeep of indexValuesToKeep) {
    url.searchParams.append("index", toKeep);
  }

  let init: RequestInit = {
    method: request.method,
    body: request.body,
    headers: request.headers,
    signal: request.signal,
  };

  if (init.body) {
    (init as { duplex: "half" }).duplex = "half";
  }

  return new Request(url.href, init);
}

export const makeStyleTag = (
  target?: InsertionTarget | undefined,
  nonce?: string | undefined
): HTMLStyleElement => {
  const head = document.head;
  const parent = target || head;
  const style = document.createElement('style');
  const prevStyle = findLastStyleTag(parent);
  const nextSibling = prevStyle !== undefined ? prevStyle.nextSibling : null;

  style.setAttribute(SC_ATTR, SC_ATTR_ACTIVE);
  style.setAttribute(SC_ATTR_VERSION, SC_VERSION);

  const resolvedNonce = nonce || getNonce();

  if (resolvedNonce) style.setAttribute('nonce', resolvedNonce);

  parent.insertBefore(style, nextSibling);

  return style;
};

export const getSheet = (tag: HTMLStyleElement): CSSStyleSheet => {
  if (tag.sheet) {
    return tag.sheet;
  }

  // Avoid Firefox quirk where the style element might not have a sheet property.
  // Use the tag's root node to find styleSheets; document.styleSheets doesn't
  // include sheets inside shadow roots.
  const root = tag.getRootNode() as Document | ShadowRoot;
  const styleSheets = root.styleSheets ?? document.styleSheets;
  for (let i = 0, l = styleSheets.length; i < l; i++) {
    const sheet = styleSheets[i];
    if (sheet.ownerNode === tag) {
      // `document.styleSheets`/`ShadowRoot.styleSheets` is typed as
      // `StyleSheetList`, whose entries are `CSSStyleSheet` at runtime
      // but the iteration return type widens to `StyleSheet`.
      return sheet as CSSStyleSheet;
    }
  }

  throw styledError(17);
};

export const outputSheet = (sheet: Sheet) => {
  const tag = sheet.getTag();
  const { length, groupSizes } = tag;

  let css = '';
  for (let group = 0; group < length; group++) {
    if (groupSizes[group] === 0) continue;

    const id = idForGroup(group);
    if (id === undefined) continue;

    const names = sheet.names.get(id);
    if (names === undefined || !names.size) continue;

    const rules = tag.getGroup(group);
    if (rules.length === 0) continue;

    const selector = SC_ATTR + '.g' + group + '[id="' + id + '"]';

    let content = '';
    for (const name of names) {
      if (name.length > 0) {
        content += name + ',';
      }
    }

    // The marker follows the rules so rehydration can collect them first.
    css += rules + selector + '{content:"' + content + '"}' + SPLITTER;
  }

  return css;
};

const isShadowRoot = (node: InsertionTarget | Node): node is ShadowRoot => {
  return (
    (typeof ShadowRoot !== 'undefined' && node instanceof ShadowRoot) ||
    ('host' in node &&
      // https://dom.spec.whatwg.org/#dom-node-document_fragment_node
      node.nodeType === 11)
  );
};

export const getRehydrationContainer = (
  target?: InsertionTarget | undefined
): Document | ShadowRoot => {
  if (!target) {
    return document;
  }

  if (isShadowRoot(target)) {
    return target;
  }

  if ('getRootNode' in target) {
    const root = (target as HTMLElement).getRootNode();
    if (isShadowRoot(root)) {
      return root;
    }
  }

  return document;
};

// Add a callback function to a list of keyed callback functions and return
// the unsubscribe function.
export const subscribeCallback = (
  key: string,
  callbacks: Record<string, Callback[]>,
  callback: Callback
) => {
  const keyedRevalidators = callbacks[key] || (callbacks[key] = [])
  keyedRevalidators.push(callback)

  return () => {
    const index = keyedRevalidators.indexOf(callback)

    if (index >= 0) {
      // O(1): faster than splice
      keyedRevalidators[index] = keyedRevalidators[keyedRevalidators.length - 1]
      keyedRevalidators.pop()
    }
  }
}

function isStyleVisible(element: Element) {
  const windowObject = getOwnerWindow(element);
  if (
    !(element instanceof windowObject.HTMLElement) &&
    !(element instanceof windowObject.SVGElement)
  ) {
    return false;
  }

  let {display, visibility} = element.style;

  let isVisible = display !== 'none' && visibility !== 'hidden' && visibility !== 'collapse';

  if (isVisible) {
    const {getComputedStyle} = getOwnerWindow(element);
    let {display: computedDisplay, visibility: computedVisibility} = getComputedStyle(element);

    isVisible =
      computedDisplay !== 'none' &&
      computedVisibility !== 'hidden' &&
      computedVisibility !== 'collapse';
  }

  return isVisible;
}

export function stagger(
    duration: number = 0.1,
    { startDelay = 0, from = 0, ease }: StaggerOptions = {}
): DynamicOption<number> {
    return (i: number, total: number) => {
        const fromIndex =
            typeof from === "number" ? from : getOriginIndex(from, total)
        const distance = Math.abs(fromIndex - i)
        let delay = duration * distance

        if (ease) {
            const maxDelay = total * duration
            const easingFunction = easingDefinitionToFunction(ease)
            delay = easingFunction(delay / maxDelay) * maxDelay
        }

        return startDelay + delay
    }
}

import isObject from './isObject';

export default function extractFormValues<
  T extends object,
  K extends Record<string, unknown>,
>(fieldsState: T, formValues: K) {
  const values: Record<string, unknown> = {};

  for (const key in fieldsState) {
    if (fieldsState.hasOwnProperty(key)) {
      const fieldState = fieldsState[key];
      const fieldValue = formValues[key];

      if (fieldState && isObject(fieldState) && fieldValue) {
        const nestedFieldsState = extractFormValues(
          fieldState,
          fieldValue as K,
        );

        if (isObject(nestedFieldsState)) {
          values[key] = nestedFieldsState;
        }
      } else if (fieldsState[key]) {
        values[key] = fieldValue;
      }
    }
  }

  return values;
}

import deepEqual from '../utils/deepEqual';
import isNullOrUndefined from '../utils/isNullOrUndefined';
import isObject from '../utils/isObject';
import isPrimitive from '../utils/isPrimitive';
import isUndefined from '../utils/isUndefined';
import objectHasFunction from '../utils/objectHasFunction';

function isTraversable<T>(value: T): boolean {
  return Array.isArray(value) || (isObject(value) && !objectHasFunction(value));
}

function markFieldsDirty<T>(data: T, fields: Record<string, any> = {}) {
  for (const key in data) {
    const value = data[key];

    if (isTraversable(value)) {
      fields[key] = Array.isArray(value) ? [] : {};
      markFieldsDirty(value, fields[key]);
    } else if (!isUndefined(value)) {
      fields[key] = true;
    }
  }

  return fields;
}

import type { ValidationModeFlags } from '../types';

export default (
  isBlurEvent: boolean,
  isTouched: boolean,
  isSubmitted: boolean,
  reValidateMode: Pick<ValidationModeFlags, 'isOnBlur' | 'isOnChange'>,
  mode: Partial<ValidationModeFlags>,
) => {
  if (mode.isOnAll) {
    return false;
  } else if (!isSubmitted && mode.isOnTouch) {
    return !(isTouched || isBlurEvent);
  } else if (isSubmitted ? reValidateMode.isOnBlur : mode.isOnBlur) {
    return !isBlurEvent;
  } else if (isSubmitted ? reValidateMode.isOnChange : mode.isOnChange) {
    return isBlurEvent;
  }
  return true;
};

function findStaticBaseDecl(ast: Root, prop: string): string | undefined | null {
  const camelTarget = camelizeProp(prop);
  for (let i = 0; i < ast.length; i++) {
    const node = ast[i];
    if (node.kind !== NodeKind.Decl) continue;
    if (typeof node.prop !== 'string') continue;
    const exact = node.prop === prop;
    const camelMatch = !exact && camelizeProp(node.prop) === camelTarget;
    if (!exact && !camelMatch) continue;
    const v = node.value;
    if (typeof v !== 'string') return null;
    // Kebab-vs-camel mismatch: the runtime value may have been
    // transformed by a polyfill (e.g. `accent-color: auto` resolves to a
    // PlatformColor). Bail so the render path uses the resolved value.
    if (camelMatch) return null;
    return v;
  }
  return undefined;
}
